#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-12

# test-continue-on-block-pattern.sh
#
# Exercises the hook test harness (lib/run-hook-fixture.mjs) against
# known-shape fixture hooks. Validates the three core HookResult shapes:
#   1. silent success (continue:true, no stopReason)
#   2. block (continue:false, stopReason + permissionDecisionReason populated)
#   3. continue-on-block (continue:true, but carrying an advisory reason)
#
# Exit codes: 0 = all assertions passed, 1 = any failed.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
FIXTURE_DRIVER="$SCRIPT_DIR/lib/run-hook-fixture.mjs"

TMP_DIR="$(mktemp -d)"
trap 'rm -rf "$TMP_DIR"' EXIT

PASS=0
FAIL=0

red()   { printf '\033[0;31m%s\033[0m' "$1"; }
green() { printf '\033[0;32m%s\033[0m' "$1"; }

# --- write three tiny hook fixtures ----------------------------------------
# Each implements the HookFn shape: (input, ctx) -> HookResult.

cat > "$TMP_DIR/hook-silent.mjs" <<'EOF'
export function run(input, _ctx) {
  return { continue: true, suppressOutput: true };
}
EOF

cat > "$TMP_DIR/hook-block.mjs" <<'EOF'
export function run(input, _ctx) {
  const path = input?.tool_input?.file_path || '<unknown>';
  const reason = `Refusing write to ${path}: protected path`;
  return {
    continue: false,
    stopReason: reason,
    hookSpecificOutput: {
      permissionDecision: 'deny',
      permissionDecisionReason: reason,
    },
  };
}
EOF

cat > "$TMP_DIR/hook-advisory.mjs" <<'EOF'
export function run(input, _ctx) {
  // continue-on-block: we surface an advisory via additionalContext but
  // do NOT halt the operation.
  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      hookEventName: 'PostToolUse',
      additionalContext: '[advisory] check stale imports in nearby files',
    },
  };
}
EOF

# --- harness helpers -------------------------------------------------------

# run_hook FIXTURE INPUT_JSON  →  prints the HookResult JSON to stdout
run_hook() {
  local fixture="$1"
  local input_json="$2"
  node "$FIXTURE_DRIVER" "$fixture" --input "$input_json"
}

# assert_block REASON_SUBSTR  (reads HookResult JSON from stdin)
assert_block() {
  local needle="$1"
  local label="$2"
  local json
  json="$(cat)"
  local continue_val stop_reason perm_reason
  continue_val=$(printf '%s' "$json" | node -e 'let d="";process.stdin.on("data",c=>d+=c).on("end",()=>{const j=JSON.parse(d);process.stdout.write(String(j.continue))})')
  stop_reason=$(printf '%s' "$json"  | node -e 'let d="";process.stdin.on("data",c=>d+=c).on("end",()=>{const j=JSON.parse(d);process.stdout.write(String(j.stopReason||""))})')
  perm_reason=$(printf '%s' "$json"  | node -e 'let d="";process.stdin.on("data",c=>d+=c).on("end",()=>{const j=JSON.parse(d);process.stdout.write(String(j.hookSpecificOutput?.permissionDecisionReason||""))})')

  if [[ "$continue_val" != "false" ]]; then
    red "FAIL"; echo " [$label] expected continue=false, got '$continue_val'"
    FAIL=$((FAIL+1)); return
  fi
  if [[ "$stop_reason" != *"$needle"* && "$perm_reason" != *"$needle"* ]]; then
    red "FAIL"; echo " [$label] expected reason to contain '$needle' (stopReason='$stop_reason' perm='$perm_reason')"
    FAIL=$((FAIL+1)); return
  fi
  green "PASS"; echo " [$label] blocked with reason matching '$needle'"
  PASS=$((PASS+1))
}

# assert_silent_success LABEL (reads HookResult JSON from stdin)
assert_silent_success() {
  local label="$1"
  local json
  json="$(cat)"
  local continue_val stop_reason
  continue_val=$(printf '%s' "$json" | node -e 'let d="";process.stdin.on("data",c=>d+=c).on("end",()=>{const j=JSON.parse(d);process.stdout.write(String(j.continue))})')
  stop_reason=$(printf '%s' "$json"  | node -e 'let d="";process.stdin.on("data",c=>d+=c).on("end",()=>{const j=JSON.parse(d);process.stdout.write(String(j.stopReason||""))})')

  if [[ "$continue_val" != "true" ]]; then
    red "FAIL"; echo " [$label] expected continue=true, got '$continue_val'"
    FAIL=$((FAIL+1)); return
  fi
  if [[ -n "$stop_reason" ]]; then
    red "FAIL"; echo " [$label] expected no stopReason, got '$stop_reason'"
    FAIL=$((FAIL+1)); return
  fi
  green "PASS"; echo " [$label] silent success"
  PASS=$((PASS+1))
}

# assert_advisory_continue NEEDLE LABEL  (reads HookResult JSON from stdin)
#   continue=true with an additionalContext substring match — the "continue
#   on block" advisory pattern.
assert_advisory_continue() {
  local needle="$1"
  local label="$2"
  local json
  json="$(cat)"
  local continue_val ctx
  continue_val=$(printf '%s' "$json" | node -e 'let d="";process.stdin.on("data",c=>d+=c).on("end",()=>{const j=JSON.parse(d);process.stdout.write(String(j.continue))})')
  ctx=$(printf '%s' "$json"          | node -e 'let d="";process.stdin.on("data",c=>d+=c).on("end",()=>{const j=JSON.parse(d);process.stdout.write(String(j.hookSpecificOutput?.additionalContext||""))})')

  if [[ "$continue_val" != "true" ]]; then
    red "FAIL"; echo " [$label] expected continue=true, got '$continue_val'"
    FAIL=$((FAIL+1)); return
  fi
  if [[ "$ctx" != *"$needle"* ]]; then
    red "FAIL"; echo " [$label] expected additionalContext to contain '$needle' (got '$ctx')"
    FAIL=$((FAIL+1)); return
  fi
  green "PASS"; echo " [$label] continued with advisory matching '$needle'"
  PASS=$((PASS+1))
}

# --- sample assertions -----------------------------------------------------

echo "Running hook harness assertions..."

# Persist PASS/FAIL across pipeline subshells via a temp counter file.
COUNTER="$TMP_DIR/counter"
echo "0 0" > "$COUNTER"
bump() {
  # bump <pass-delta> <fail-delta>
  read -r p f < "$COUNTER"
  echo "$((p + ${1:-0})) $((f + ${2:-0}))" > "$COUNTER"
}
# Re-bind PASS/FAIL increments to file-backed counter.
PASS_FILE_BUMP() { bump 1 0; }
FAIL_FILE_BUMP() { bump 0 1; }

run_assert() {
  # Wraps a `run_hook ... | assert_...` pipeline and updates the file counter.
  local out
  if out="$( "$@" 2>&1 )"; then
    echo "$out"
    case "$out" in
      *PASS*) PASS_FILE_BUMP ;;
      *FAIL*) FAIL_FILE_BUMP ;;
    esac
  else
    echo "$out"
    FAIL_FILE_BUMP
  fi
}

# Use a helper function so the pipeline runs inside one subshell we can capture.
case_silent() {
  run_hook "$TMP_DIR/hook-silent.mjs" \
    '{"tool_name":"Write","tool_input":{"file_path":"/tmp/foo.ts"}}' \
    | assert_silent_success "silent hook"
}
case_block() {
  run_hook "$TMP_DIR/hook-block.mjs" \
    '{"tool_name":"Write","tool_input":{"file_path":"/etc/passwd"}}' \
    | assert_block "protected path" "block hook"
}
case_advisory() {
  run_hook "$TMP_DIR/hook-advisory.mjs" \
    '{"tool_name":"Write","tool_input":{"file_path":"/tmp/foo.ts"}}' \
    | assert_advisory_continue "stale imports" "advisory hook (continue-on-block)"
}

run_assert case_silent
run_assert case_block
run_assert case_advisory

read -r PASS FAIL < "$COUNTER"

# --- summary ---------------------------------------------------------------

echo ""
echo "================================="
echo " passed: $PASS   failed: $FAIL"
echo "================================="

if [[ $FAIL -gt 0 ]]; then
  exit 1
fi
exit 0
